The canonical service definition pattern uses Effect v4's `Context.Service<Service, Interface>()("@opencode/Name")` with a runtime string tag.

=== Pattern (from session/session.ts:451-513) ===

```ts
// 1. Define the Interface (no class, plain interface)
export interface Interface {
  readonly list: (input?: ListInput) => Effect.Effect<Info[]>
  readonly create: (input?: {...}) => Effect.Effect<Info>
  readonly get: (id: SessionID) => Effect.Effect<Info, NotFound>
  // ...
}

// 2. Define the Service class — extends Context.Service<Service, Interface>()("tag")
export class Service extends Context.Service<Service, Interface>()("@opencode/Session") {}

// 3. Optionally export a helper
export const use = serviceUse(Service)

// 4. Define the layer
// Layer.effect(Service, Effect.gen(function* () { ... return Service.of({ ... }) }))
export const layer: Layer.Layer<
  Service,
  never,
  BackgroundJob.Service | Bus.Service | Storage.Service | SyncEvent.Service | RuntimeFlags.Service
> = Layer.effect(
  Service,
  Effect.gen(function* () {
    const background = yield* BackgroundJob.Service
    const bus = yield* Bus.Service
    // ...

    // Each method is defined as a named Effect.fn
    const create = Effect.fn("Session.create")(function* (input?: {...}) {
      // ...
    })

    return Service.of({
      list,
      create,
      // ... all interface methods
    })
  }),
)

// 5. Default layer with dependencies provided
export const defaultLayer = layer.pipe(
  Layer.provide(BackgroundJob.defaultLayer),
  Layer.provide(Bus.layer),
  // ...
)
```

